'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabaseClient';
import { useAuth } from '@/context/AuthContext';
import Navbar from '@/components/Navbar';

export default function FeedPage() {
  const { user } = useAuth();
  const router = useRouter();
  const [postContent, setPostContent] = useState('');
  const [posts, setPosts] = useState([]);

  useEffect(() => {
    if (!user) router.push('/auth');
    else fetchPosts();
  }, [user]);

  const fetchPosts = async () => {
    const { data, error } = await supabase
      .from('submissions')
      .select('id, content, created_at, profiles(name, avatar_url)')
      .order('created_at', { ascending: false });

    if (!error) setPosts(data);
  };

  const handlePost = async () => {
    if (!postContent.trim()) return;
    const { error } = await supabase.from('submissions').insert([
      {
        user_id: user.id,
        content: postContent,
      },
    ]);
    if (!error) {
      setPostContent('');
      fetchPosts();
    }
  };

  if (!user) return null;

  return (
    <div className="min-h-screen bg-gray-100 text-black">
      <Navbar />

      <main className="grid grid-cols-1 md:grid-cols-4 gap-6 p-6 max-w-7xl mx-auto">
        {/* Profile Sidebar */}
        <aside className="bg-white shadow p-4 rounded-md col-span-1 text-center">
          <div className="w-24 h-24 bg-gray-200 rounded-full mx-auto mb-2" />
          <p className="font-semibold">{user.email}</p>
          <p className="text-xs text-gray-500">1 Connections | 1 Views</p>
          <button
            className="mt-3 text-sm text-purple-600 hover:underline"
            onClick={() => router.push('/profile')}
          >
            View my profile
          </button>
        </aside>

        {/* Feed Section */}
        <section className="bg-white shadow p-4 rounded-md col-span-2">
          <h3 className="font-semibold mb-2">Create a post</h3>
          <textarea
            placeholder="Write something..."
            value={postContent}
            onChange={(e) => setPostContent(e.target.value)}
            className="w-full border p-2 rounded mb-2"
          />
          <button
            onClick={handlePost}
            className="bg-purple-600 text-white px-4 py-2 rounded hover:bg-purple-700"
          >
            POST
          </button>

          <div className="mt-6 space-y-4">
            {posts.map((post) => (
              <div
                key={post.id}
                className="border-t pt-4 border-gray-200"
              >
                <div className="font-semibold text-sm">
                  {post.profiles?.name || 'Anonymous'}
                </div>
                <p className="text-gray-700">{post.content}</p>
                <div className="flex text-xs gap-4 mt-2 text-gray-500">
                  <span>❤️ 0</span>
                  <span>💬 0</span>
                  <span>🔁 0</span>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Who to Follow */}
        <aside className="bg-white shadow p-4 rounded-md col-span-1">
          <h3 className="font-semibold text-md mb-3">Who to follow</h3>
          {['Jacob Stanley', 'Eric Garcia', 'Moshe David'].map((name) => (
            <div key={name} className="mb-4 flex items-center gap-3">
              <div className="w-10 h-10 bg-gray-200 rounded-full" />
              <div>
                <p className="text-sm font-medium">{name}</p>
                <p className="text-xs text-gray-500">Designer</p>
              </div>
            </div>
          ))}
        </aside>
      </main>
    </div>
  );
}
